// ═══ Simulation Salle Serveur ═══
// Base: Temp 24°C, Humidité 45%
// Dérive progressive simulant usure climatisation

let count = context.get('count') || 0;
count++;
context.set('count', count);

// Dérive lente (simule dégradation climatisation)
let drift = Math.min(count * 0.005, 8);

// Température: 24°C ± 2.5°C + dérive
let temperature = 24 + (Math.random() * 5 - 2.5) + drift;
temperature = Math.round(temperature * 100) / 100;

// Humidité: 45% ± 6% + dérive corrélée
let humidite = 45 + (Math.random() * 12 - 6) + (drift * 0.8);
humidite = Math.round(Math.min(Math.max(humidite, 10), 99) * 100) / 100;

msg.payload = {
    zone: "salle-serveur",
    timestamp: new Date().toISOString(),
    capteurs: {
        temperature: temperature,
        humidite: humidite
    }
};
msg.topic = "iot/salle-serveur/data";

node.status({
    fill: temperature > 28 ? "red" : "green",
    shape: "dot",
    text: `T:${temperature}°C | H:${humidite}%`
});

return msg;

// ═══ Simulation Atelier Technique ═══
// Base: Vibration 2.5mm/s, Temp 35°C
// Spikes aléatoires simulant anomalies machine

let count = context.get('count') || 0;
count++;
context.set('count', count);

let drift = Math.min(count * 0.003, 5);

// Vibration: 2.5mm/s ± 1.2mm/s + drift + spikes
let vibration = 2.5 + (Math.random() * 2.4 - 1.2) + drift;

// Spike aléatoire (5% de chance) simulant défaut mécanique
if (Math.random() < 0.05) {
    vibration += 3 + Math.random() * 3;
}
vibration = Math.round(Math.max(vibration, 0.1) * 100) / 100;

// Température: 35°C ± 3°C + drift (corrélée aux vibrations)
let temperature = 35 + (Math.random() * 6 - 3) + drift * 0.8;
if (vibration > 5.0) temperature += 2; // surchauffe si vibration haute
temperature = Math.round(temperature * 100) / 100;

msg.payload = {
    zone: "atelier",
    timestamp: new Date().toISOString(),
    capteurs: {
        vibration: vibration,
        temperature: temperature
    }
};
msg.topic = "iot/atelier/data";

node.status({
    fill: vibration > 5.0 ? "red" : "green",
    shape: vibration > 5.0 ? "ring" : "dot",
    text: `V:${vibration}mm/s | T:${temperature}°C`
});

return msg;

// ═══ Simulation Local Électrique ═══
// Base: Luminosité 200 lux, Temp 30°C
// Dérive descendante luminosité (usure ampoules)

let count = context.get('count') || 0;
count++;
context.set('count', count);

let drift = Math.min(count * 0.004, 6);

// Luminosité: 200 lux ± 50 lux - drift descendante
let luminosite = 200 + (Math.random() * 100 - 50) - (drift * 15);

// Coupure intermittente (3% de chance)
if (Math.random() < 0.03) {
    luminosite = 5 + Math.random() * 25;
}
luminosite = Math.round(Math.max(luminosite, 0) * 100) / 100;

// Température: 30°C ± 2.5°C + drift
let temperature = 30 + (Math.random() * 5 - 2.5) + drift * 0.6;
temperature = Math.round(temperature * 100) / 100;

msg.payload = {
    zone: "local-electrique",
    timestamp: new Date().toISOString(),
    capteurs: {
        luminosite: luminosite,
        temperature: temperature
    }
};
msg.topic = "iot/local-electrique/data";

node.status({
    fill: luminosite < 50 ? "yellow" : "green",
    shape: "dot",
    text: `L:${luminosite}lux | T:${temperature}°C`
});

return msg;

// ═══ Formatage des données pour InfluxDB ═══
// Format: [fieldsObject, tagsObject] pour node-red-contrib-influxdb

let data = msg.payload;
if (!data || !data.capteurs || !data.zone) {
    node.warn('Données invalides: ' + JSON.stringify(data));
    return null;
}

let zone = data.zone;
let fields = {};

for (let key in data.capteurs) {
    let val = parseFloat(data.capteurs[key]);
    if (!isNaN(val)) {
        fields[key] = val;
    }
}

if (Object.keys(fields).length === 0) {
    return null;
}

// Format node-red-contrib-influxdb: [fields, tags]
msg.payload = [fields, {zone: zone}];

node.status({
    fill: "blue",
    shape: "dot",
    text: zone + ": " + Object.keys(fields).join(", ")
});

return msg;

let temp = msg.payload.capteurs.temperature;

let alerte = {
    payload: {
        type: "ALERTE_TEMPERATURE",
        zone: "salle-serveur",
        niveau: temp > 32 ? "CRITIQUE" : "WARNING",
        message: "Temperature salle serveur elevee : " + temp + " C (seuil: 28 C)",
        valeur: temp,
        seuil: 28,
        timestamp: new Date().toISOString()
    },
    topic: "alertes/salle-serveur/temperature"
};

let action = {
    payload: {
        action: "ACTIVER_VENTILATION",
        zone: "salle-serveur",
        intensite: temp > 32 ? "MAX" : "NORMAL",
        raison: "Temperature " + temp + " C depasse le seuil de 28 C",
        timestamp: new Date().toISOString()
    },
    topic: "actions/ventilation"
};

node.status({fill:"red", shape:"dot", text: "ALERTE: " + temp + " C"});
return [alerte, action];

let hum = msg.payload.capteurs.humidite;

let alerte = {
    payload: {
        type: "ALERTE_HUMIDITE",
        zone: "salle-serveur",
        niveau: hum > 85 ? "CRITIQUE" : "WARNING",
        message: "Humidite salle serveur elevee : " + hum + "% (seuil: 70%)",
        valeur: hum,
        seuil: 70,
        timestamp: new Date().toISOString()
    },
    topic: "alertes/salle-serveur/humidite"
};

let action = {
    payload: {
        action: "ACTIVER_DESHUMIDIFICATEUR",
        zone: "salle-serveur",
        intensite: hum > 85 ? "MAX" : "NORMAL",
        timestamp: new Date().toISOString()
    },
    topic: "actions/deshumidificateur"
};

node.status({fill:"yellow", shape:"dot", text: "Humidite: " + hum + "%"});
return [alerte, action];

let vib = msg.payload.capteurs.vibration;

let alerte = {
    payload: {
        type: "ALERTE_VIBRATION",
        zone: "atelier",
        niveau: vib > 7.0 ? "CRITIQUE" : "WARNING",
        message: "Vibration excessive atelier : " + vib + "mm/s (seuil: 5.0mm/s)",
        valeur: vib,
        seuil: 5.0,
        timestamp: new Date().toISOString()
    },
    topic: "alertes/atelier/vibration"
};

let action = {
    payload: {
        action: "ARRET_MACHINE",
        zone: "atelier",
        urgence: vib > 7.0 ? "IMMEDIAT" : "PROGRESSIF",
        raison: "Vibration " + vib + "mm/s depasse le seuil de 5.0mm/s",
        timestamp: new Date().toISOString()
    },
    topic: "actions/arret-machine"
};

node.status({fill:"red", shape:"ring", text: "VIBRATION: " + vib + "mm/s"});
return [alerte, action];

let temp = msg.payload.capteurs.temperature;

msg.payload = {
    type: "ALERTE_TEMPERATURE",
    zone: "atelier",
    niveau: temp > 45 ? "CRITIQUE" : "WARNING",
    message: "Surchauffe atelier : " + temp + " C (seuil: 40 C)",
    valeur: temp,
    seuil: 40,
    timestamp: new Date().toISOString()
};
msg.topic = "alertes/atelier/temperature";

node.status({fill:"red", shape:"dot", text: "Surchauffe: " + temp + " C"});
return msg;

let lux = msg.payload.capteurs.luminosite;

let alerte = {
    payload: {
        type: "ALERTE_LUMINOSITE",
        zone: "local-electrique",
        niveau: lux < 20 ? "CRITIQUE" : "WARNING",
        message: "Luminosite insuffisante local electrique : " + lux + " lux (seuil: 50 lux)",
        valeur: lux,
        seuil: 50,
        timestamp: new Date().toISOString()
    },
    topic: "alertes/local-electrique/luminosite"
};

let action = {
    payload: {
        action: "ACTIVER_ECLAIRAGE",
        zone: "local-electrique",
        intensite: lux < 20 ? "MAX" : "NORMAL",
        raison: "Luminosite " + lux + " lux sous le seuil de 50 lux",
        timestamp: new Date().toISOString()
    },
    topic: "actions/eclairage"
};

node.status({fill:"yellow", shape:"dot", text: "Lux: " + lux});
return [alerte, action];

let temp = msg.payload.capteurs.temperature;

msg.payload = {
    type: "ALERTE_TEMPERATURE",
    zone: "local-electrique",
    niveau: temp > 40 ? "CRITIQUE" : "WARNING",
    message: "Temperature elevee local electrique : " + temp + " C (seuil: 35 C)",
    valeur: temp,
    seuil: 35,
    timestamp: new Date().toISOString()
};
msg.topic = "alertes/local-electrique/temperature";

node.status({fill:"red", shape:"dot", text: "Temp LE: " + temp + " C"});
return msg;

const token = env.get('TELEGRAM_BOT_TOKEN');
const chatId = env.get('TELEGRAM_CHAT_ID');
if (!token || !chatId || token === 'YOUR_BOT_TOKEN' || token === '') {
    node.status({fill:'grey',shape:'ring',text:'Telegram non configure'});
    return null;
}
const key = 'tg_' + msg.topic;
const now = Date.now();
const lastSent = context.get(key) || 0;
if (now - lastSent < 300000) {
    const s = Math.round((300000-(now-lastSent))/1000);
    node.status({fill:'yellow',shape:'ring',text:'Cooldown '+s+'s'});
    return null;
}
context.set(key, now);
const p = msg.payload;
const niveau = p.niveau || 'INFO';
const tag = niveau === 'CRITIQUE' ? '[CRITIQUE]' : '[WARNING]';
const ts = new Date().toLocaleString('fr-FR');
const text = tag + ' *ALERTE ' + niveau + '*\n\nZone : *' + (p.zone||msg.topic) + '*\nProbleme : ' + (p.message||'Alerte') + '\nValeur : *' + p.valeur + '* (seuil : ' + p.seuil + ')\nHeure : ' + ts + '\n\n_Hackathon IoT 2026 - Equipe 01_';
msg.url = 'https://api.telegram.org/bot' + token + '/sendMessage';
msg.method = 'POST';
msg.payload = {chat_id:chatId, text:text, parse_mode:'Markdown'};
msg.headers = {'Content-Type':'application/json'};
node.status({fill:'blue',shape:'dot',text:'Envoye: '+niveau});
return msg;

const emailTo = env.get('EMAIL_TO');
const emailFrom = env.get('EMAIL_FROM');
if (!emailTo || emailTo === '' || emailTo === 'votre.email@gmail.com') {
    node.status({fill:'grey',shape:'ring',text:'Email non configure'});
    return null;
}
const key = 'em_' + msg.topic;
const now = Date.now();
const lastSent = context.get(key) || 0;
if (now - lastSent < 600000) {
    node.status({fill:'yellow',shape:'ring',text:'Cooldown email'});
    return null;
}
context.set(key, now);
const p = msg.payload;
const niveau = p.niveau || 'INFO';
const color = niveau === 'CRITIQUE' ? '#F43F5E' : '#F59E0B';
const ts = new Date().toLocaleString('fr-FR');
msg.to = emailTo;
msg.from = emailFrom || emailTo;
msg.subject = '[IoT ALERTE ' + niveau + '] ' + (p.zone||msg.topic).toUpperCase();
msg.payload = '<html><body style="font-family:Arial,sans-serif;background:#0B1929;color:#E2E8F0;padding:24px"><div style="max-width:600px;margin:auto;background:#122A45;border-radius:12px;padding:24px;border-left:5px solid '+color+'"><h2 style="color:'+color+';margin-top:0">ALERTE '+niveau+'</h2><p><b>Zone :</b> '+(p.zone||msg.topic)+'</p><p><b>Probleme :</b> '+(p.message||'Alerte detectee')+'</p><p><b>Valeur :</b> <span style="font-size:1.4em;color:'+color+'">'+p.valeur+'</span></p><p><b>Seuil :</b> '+p.seuil+'</p><p><b>Heure :</b> '+ts+'</p><hr style="border-color:#1E3A5F"><p style="color:#94A3B8;font-size:0.8em">Hackathon IoT 2026 - Equipe 01 - Satom IT Learning Solutions</p></div></body></html>';
msg.contentType = 'text/html';
node.status({fill:'blue',shape:'dot',text:'Email: '+niveau});
return msg;
